1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	const CURSE_SURCHARGE_RATE = 0.5;
8	const BASE_PREMIUMS: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	const BLOCK_SIZE = 3;
19	const BLOCK_BASE_PREMIUM = 60;
20	
21	const unitBasePremium = (type: string): number => BASE_PREMIUMS[type] ?? 0;
22	
23	const isComponentBlock = (type: string, count: number): boolean =>
24	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
25	
26	const groupBasePremium = (type: string, count: number): number =>
27	  isComponentBlock(type, count) ? BLOCK_BASE_PREMIUM : count * unitBasePremium(type);
28	
29	const countByType = (items: Item[]): Map<string, number> =>
30	  items.reduce(
31	    (counts, item) => counts.set(item.type, (counts.get(item.type) ?? 0) + 1),
32	    new Map<string, number>(),
33	  );
34	
35	const itemsBasePremium = (items: Item[]): number =>
36	  [...countByType(items)].reduce(
37	    (total, [type, count]) => total + groupBasePremium(type, count),
38	    0,
39	  );
40	
41	const itemModifierSurcharge = (item: Item): number => {
42	  const base = unitBasePremium(item.type);
43	  return (item.cursed ? base * CURSE_SURCHARGE_RATE : 0);
44	};
45	
46	const itemsModifierSurcharge = (items: Item[]): number =>
47	  items.reduce((total, item) => total + itemModifierSurcharge(item), 0);
48	
49	const quotePremium = (items: Item[]): number => {
50	  const base = itemsBasePremium(items);
51	  const modifierSurcharge = itemsModifierSurcharge(items);
52	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
53	  return Math.ceil(base + modifierSurcharge + firstInsuranceSurcharge + PROCESSING_FEE);
54	};
55	
56	export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => ({
57	  results: scenario.steps.map((step) => ({ premium: quotePremium(step.items) })),
58	});
